<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>绝区零 RPG · 角色创建面板</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Segoe UI','Microsoft YaHei',sans-serif;background:#1a1a2e;color:#e0e0e0;min-height:100vh;display:flex;justify-content:center;padding:20px}
.container{max-width:720px;width:100%}
.header{text-align:center;padding:30px 0 20px}
.header h1{font-size:28px;color:#f0c040;letter-spacing:2px;text-shadow:0 0 20px rgba(240,192,64,.3)}
.header p{color:#888;font-size:14px;margin-top:8px}
.card{background:#16213e;border-radius:16px;padding:24px;margin-bottom:16px;border:1px solid #1e2d50;box-shadow:0 4px 20px rgba(0,0,0,.3)}
.card h2{font-size:16px;color:#f0c040;margin-bottom:16px;padding-bottom:8px;border-bottom:1px solid #1e2d50;display:flex;align-items:center;gap:8px}
.card h2 .badge{font-size:11px;padding:2px 8px;border-radius:10px;color:#fff}
.badge-green{background:#2a8a4a}
.badge-orange{background:#b86b2c}
.badge-blue{background:#2a6a8a}
.badge-purple{background:#7a4aaa}

/* Route selector */
.route-cards{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px}
.route-card{padding:20px 16px;border-radius:14px;border:2px solid #1e2d50;background:#0f1b33;color:#ccc;cursor:pointer;text-align:center;transition:all .25s}
.route-card:hover{background:#1a2d50;border-color:#3a5a80;transform:translateY(-2px)}
.route-card.active{border-color:#f0c040;background:#1a2d40;color:#f0c040;box-shadow:0 0 20px rgba(240,192,64,.2)}
.route-card .icon{font-size:36px;display:block;margin-bottom:10px}
.route-card .label{font-weight:700;font-size:16px;margin-bottom:6px}
.route-card .desc{font-size:12px;color:#888;line-height:1.5}
.route-card.active .desc{color:#bba060}

/* Phaethon choice */
.phaethon-choice{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px}
.phaethon-card{padding:16px;border-radius:12px;border:2px solid #1e2d50;background:#0f1b33;cursor:pointer;text-align:center;transition:all .2s}
.phaethon-card:hover{background:#1a2d50;border-color:#3a5a80}
.phaethon-card.active{border-color:#f0c040;background:#1a2d40}
.phaethon-card .avatar{font-size:40px;display:block;margin-bottom:8px}
.phaethon-card .name{font-size:20px;font-weight:700;color:#e0e0e0}
.phaethon-card.active .name{color:#f0c040}
.phaethon-card .role{font-size:12px;color:#888;margin-top:4px}

/* Presets */
.presets{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:20px}
.preset-btn{padding:14px 8px;border-radius:12px;border:2px solid #1e2d50;background:#0f1b33;color:#ccc;cursor:pointer;text-align:center;transition:all .2s;font-size:13px}
.preset-btn:hover{background:#1a2d50;border-color:#3a5a80;transform:translateY(-2px)}
.preset-btn.active{border-color:#f0c040;background:#1a2d40;color:#f0c040;box-shadow:0 0 15px rgba(240,192,64,.2)}
.preset-btn .icon{font-size:28px;display:block;margin-bottom:6px}
.preset-btn .label{font-weight:600;font-size:13px}
.preset-btn .desc{font-size:11px;color:#888;margin-top:4px}

/* Custom form */
.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}
.form-group{display:flex;flex-direction:column}
.form-group.full{grid-column:1/-1}
.form-group label{font-size:12px;color:#999;margin-bottom:4px;font-weight:500}
.form-group input,.form-group select{background:#0f1b33;border:1px solid #1e2d50;border-radius:8px;padding:10px 12px;color:#e0e0e0;font-size:14px;outline:none;transition:border .2s}
.form-group input:focus,.form-group select:focus{border-color:#f0c040}
.form-group select{cursor:pointer;appearance:auto}
.form-group select option{background:#16213e;color:#e0e0e0}
.form-group .hint{font-size:11px;color:#666;margin-top:4px}

/* Bangboo */
.bb-card{padding:12px;border-radius:10px;border:2px solid #1e2d50;background:#0f1b33;cursor:pointer;transition:all .2s;text-align:center}
.bb-card:hover{border-color:#4fc3f7;background:#102540;transform:translateY(-2px)}
.bb-card.active{border-color:#4fc3f7;background:#0a2a3f;box-shadow:0 0 12px rgba(79,195,247,.2)}
.bb-card .bb-name{font-size:14px;font-weight:700;color:#e0e0e0;margin-bottom:4px}
.bb-card .bb-faction{font-size:10px;color:#888;margin-bottom:3px}
.bb-card .bb-skill{font-size:11px;color:#4fc3f7}

/* Start button */
.start-section{text-align:center;padding:10px 0 20px}
.start-btn{background:linear-gradient(135deg,#f0c040,#d4a020);border:none;border-radius:14px;padding:16px 48px;color:#1a1a2e;font-size:18px;font-weight:700;cursor:pointer;letter-spacing:2px;transition:all .3s;box-shadow:0 4px 20px rgba(240,192,64,.3)}
.start-btn:hover{transform:translateY(-3px);box-shadow:0 8px 30px rgba(240,192,64,.4)}
.start-btn:active{transform:translateY(0)}

/* Hidden sections */
.hidden-section{display:none}
.hidden-section.show{display:block}

.footer{text-align:center;padding:20px;color:#555;font-size:12px}
</style>
</head>
<body>
<div class="container">
  <div class="header">
    <h1>⚡ 绝区零 · 角色创建</h1>
    <p>选择你的身份，开始在新艾利都的冒险</p>
  </div>

  <!-- Step 1: Choose Route -->
  <div class="card" id="step-route">
    <h2>📋 STEP 1: 选择开局模式</h2>
    <div class="route-cards">
      <div class="route-card active" data-route="phaethon" onclick="selectRoute('phaethon')">
        <span class="icon">🎮</span>
        <span class="label">法厄同</span>
        <span class="desc">传奇绳匠，经营Random Play录像店，通过HDD远程操控伊埃斯探索空洞</span>
      </div>
      <div class="route-card" data-route="custom" onclick="selectRoute('custom')">
        <span class="icon">🆕</span>
        <span class="label">非法厄同</span>
        <span class="desc">自定义身份——普通居民、治安官、盗洞客……在新艾利都谱写属于你的故事</span>
      </div>
    </div>
  </div>

  <!-- Phaethon Section -->
  <div class="card hidden-section show" id="phaethon-section">
    <h2>🎮 STEP 2: 选择法厄同身份 <span class="badge badge-purple">法厄同线</span></h2>
    <p style="color:#888;font-size:13px;margin-bottom:12px">选择扮演哲还是铃。法厄同模式下，你将以HDD远程操控伊埃斯的方式探索空洞。</p>
    <div class="phaethon-choice" id="phaethon-choices">
      <div class="phaethon-card active" data-character="wise" onclick="selectPhaethon('wise')">
        <span class="avatar">♂</span>
        <span class="name">哲 (Wise)</span>
        <span class="role">兄 · 冷静聪慧 · 灰色短发</span>
      </div>
      <div class="phaethon-card" data-character="belle" onclick="selectPhaethon('belle')">
        <span class="avatar">♀</span>
        <span class="name">铃 (Belle)</span>
        <span class="role">妹 · 元气开朗 · 深蓝短发</span>
      </div>
    </div>
  </div>

  <!-- Custom Section -->
  <div class="card hidden-section" id="custom-section">
    <h2>📋 STEP 2: 选择开局身份</h2>
    <div class="presets" id="presets">
      <div class="preset-btn active" data-preset="resident">
        <span class="icon">🏠</span>
        <span class="label">普通居民</span>
        <span class="desc">六分街的平凡日常</span>
      </div>
      <div class="preset-btn" data-preset="officer">
        <span class="icon">👮</span>
        <span class="label">治安官</span>
        <span class="desc">NEPS基层执法者</span>
      </div>
      <div class="preset-btn" data-preset="raider">
        <span class="icon">⛏️</span>
        <span class="label">盗洞客</span>
        <span class="desc">空洞边缘的拾荒者</span>
      </div>
    </div>
  </div>

  <!-- Custom Form -->
  <div class="card hidden-section" id="form-section">
    <h2>✏️ STEP 3: 自定义角色 <span class="badge badge-orange">非法厄同</span></h2>
    <div class="form-grid" id="form">
      <div class="form-group">
        <label>角色姓名</label>
        <input type="text" id="name" placeholder="输入你的名字" value="">
      </div>
      <div class="form-group">
        <label>种族</label>
        <select id="race">
          <option value="人类">人类</option>
          <option value="猫希人">猫希人</option>
          <option value="虎希人">虎希人</option>
          <option value="犬希人">犬希人</option>
          <option value="狼希人">狼希人</option>
          <option value="鲨希人">鲨希人</option>
          <option value="熊希人">熊希人</option>
          <option value="鼠希人">鼠希人</option>
          <option value="兔希人">兔希人</option>
          <option value="鬼族">鬼族</option>
          <option value="精灵">精灵</option>
          <option value="吸血鬼">吸血鬼</option>
          <option value="智能构造体">智能构造体</option>
        </select>
      </div>
      <div class="form-group">
        <label>性别</label>
        <select id="gender">
          <option value="男">男</option>
          <option value="女">女</option>
        </select>
      </div>
      <div class="form-group">
        <label>年龄</label>
        <input type="number" id="age" value="25" min="10" max="120">
      </div>
      <div class="form-group full">
        <label>背景简述</label>
        <input type="text" id="bio" placeholder="一句话概括你的角色背景" value="新艾利都的普通市民，过着平凡的日常生活">
      </div>
      <div class="form-group">
        <label>以太适应性 (0-100)</label>
        <input type="number" id="ether" value="45" min="0" max="100">
        <span class="hint">低于50无法独自进入空洞</span>
      </div>
      <div class="form-group">
        <label>战斗能力</label>
        <select id="combat">
          <option value="无">无</option>
          <option value="弱">弱</option>
          <option value="中" selected>中</option>
          <option value="强">强</option>
          <option value="顶尖">顶尖</option>
        </select>
      </div>
      <div class="form-group">
        <label>所属势力</label>
        <select id="faction">
          <option value="无">无 / 独立</option>
          <option value="新艾利都治安局（N.E.P.S.）">治安局（N.E.P.S.）</option>
          <option value="空洞调查协会（H.I.A.）">H.I.A.</option>
          <option value="防卫军">防卫军</option>
          <option value="狡兔屋">狡兔屋</option>
          <option value="白祇重工">白祇重工</option>
          <option value="卡吕冬之子">卡吕冬之子</option>
          <option value="TOPS财团">TOPS财团</option>
          <option value="独立绳匠">独立绳匠</option>
        </select>
      </div>
      <div class="form-group">
        <label>特殊能力 / 特长</label>
        <input type="text" id="special" placeholder="无" value="无">
        <span class="hint">如：机械维修、黑客、医疗等</span>
      </div>
    </div>
  </div>

  <!-- Bangboo Section -->
  <div class="card hidden-section" id="bangboo-section">
    <h2>🤖 STEP 4: 邦布伙伴 <span class="badge badge-blue">初始选择</span></h2>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:8px" id="bangboo-presets">
    </div>
  </div>

  <!-- Start Button -->
  <div class="start-section">
    <button class="start-btn" onclick="startAdventure()">⚡ 开始冒险</button>
  </div>

  <div class="footer">
    绝区零 RPG · 角色创建面板 v2.0
  </div>
</div>

<script>
let currentRoute = 'phaethon';
let selectedPhaethon = 'wise';
let currentPreset = 'resident';

const PRESETS = {
  resident: {
    name:'',race:'人类',gender:'男',age:25,
    bio:'新艾利都的普通市民，过着平凡的日常生活',
    ether:45,combat:'无',faction:'无',special:'无'
  },
  officer: {
    name:'',race:'人类',gender:'男',age:28,
    bio:'新艾利都治安局的一名基层治安官，日常巡逻六分街及周边区域',
    ether:55,combat:'中',faction:'新艾利都治安局（N.E.P.S.）',special:'标准治安官训练、以太抑制装备使用'
  },
  raider: {
    name:'',race:'猫希人',gender:'男',age:30,
    bio:'经验丰富的盗洞客，以探索空洞寻找值钱物资为生',
    ether:70,combat:'强',faction:'独立',special:'空洞生存经验、以骸战斗技巧、简易萝卜绘制'
  }
};

function selectRoute(route) {
  currentRoute = route;
  document.querySelectorAll('.route-card').forEach(c => c.classList.remove('active'));
  document.querySelector(`[data-route="${route}"]`).classList.add('active');
  
  document.getElementById('phaethon-section').classList.toggle('show', route === 'phaethon');
  document.getElementById('custom-section').classList.toggle('show', route === 'custom');
  document.getElementById('form-section').classList.toggle('show', route === 'custom');
  document.getElementById('bangboo-section').classList.toggle('show', route === 'custom');
}

