    narrative = presetNarratives[currentPreset] || presetNarratives.resident;
  }
  
  const patchStr = JSON.stringify(patches);
  const hiddenDirective = `<span style="display:none;">
<UpdateVariable>
<JSONPatch>
${patchStr}
</JSONPatch>
</UpdateVariable>
</span>`;
  
  const finalPrompt = `/send ${narrative}\n\n${hiddenDirective}|/trigger`;
  
  if (typeof triggerSlash === 'function') {
    triggerSlash(finalPrompt);
  } else {
    alert("无法自动发送。请复制以下文本手动发送：\n\n" + narrative);
  }
}
</script>
