      <div class="npc-g-card" onclick="pickGear('身体')"><span class="npc-g-label">身体</span><span class="npc-g-val" style="font-size:11px" id="h-gear-body">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('足部')"><span class="npc-g-label">足部</span><span class="npc-g-val" style="font-size:11px" id="h-gear-foot">空置</span></div>
      <div class="npc-g-card" onclick="pickGear('饰品')"><span class="npc-g-label">饰品</span><span class="npc-g-val" style="font-size:11px" id="h-gear-acc">空置</span></div>
    </div>
