    <div id="owned-bangboo-list" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:8px"></div>
    <div style="margin-top:8px;display:flex;gap:6px">
      <input id="bb-new-name" placeholder="新邦布名" style="flex:1;background:#0b0e17;border:1px solid var(--border);border-radius:6px;padding:6px 8px;color:var(--text);font-size:12px;outline:none">
